#include <stdio.h>

int main(void) {
    int n = 0;
    scanf("%d", &n);

    int arr[n];
    int tmp[n];

    int ones = 0;

    for (int i = 0; i < n; i++) {
        scanf("%d", arr + i);
        if (arr[i] == 1) {
            ones++;
        }
    }

    int a = 0;
    int b = 0;
    int c = 0;
    int d = 0;

    for (int i = 0; i < n; i++) {
        if (arr[i] == 1) {
            a++;
        } else {
            a--;
        }

        if (a > 0) {
            a = 0;
        } else if (b > a) {
            b = a;
            c = i;
        }

        tmp[i] = a;
    }

    d = c;

    while (d >= 0 && tmp[d] < 0) {
        d--;
    }

    if (c != d) {
        for (int i = d + 1; i <= c; i++) {
            if (arr[i] == 0) {
                ones++;
            } else {
                ones--;
            }
        }
    } else {
        if (arr[c] == 0) {
            ones++;
        } else {
            ones--;
        }
    }

    printf("%d\n", ones);
    return 0;
}

